func lessonPoints(l domain.Lesson) int {
	total := 0
	for _, c := range l.Challenges {
		total += c.Points
	}
	return total
}

// lessonComplete reports whether every challenge in a lesson has a passing
// submission. A lesson with no challenges is never "complete" — there's
// nothing to mark.
func lessonComplete(l domain.Lesson, completed map[int64]bool) bool {
	if len(l.Challenges) == 0 {
		return false
	}
	for _, c := range l.Challenges {
		if !completed[c.ID] {
			return false
		}
	}
	return true
}

func plural(n int) string {
	if n == 1 {
		return ""
	}
	return "s"
}

